import{_ as s,o as n,c as i,a3 as l}from"./chunks/framework.BTFg6ESq.js";const c=JSON.parse('{"title":"📤 导出与导入","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/tools/llm-chat/export-import.md","filePath":"user-guide/tools/llm-chat/export-import.md","lastUpdated":1778221347000}'),e={name:"user-guide/tools/llm-chat/export-import.md"};function t(p,a,o,r,h,d){return n(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="📤-导出与导入" tabindex="-1">📤 导出与导入 <a class="header-anchor" href="#📤-导出与导入" aria-label="Permalink to &quot;📤 导出与导入&quot;">​</a></h1><p>LLM Chat 支持将会话、分支和 Agent 导出为多种格式，也支持从外部文件导入数据。</p><h2 id="会话导出" tabindex="-1">会话导出 <a class="header-anchor" href="#会话导出" aria-label="Permalink to &quot;会话导出&quot;">​</a></h2><h3 id="导出为-markdown" tabindex="-1">导出为 Markdown <a class="header-anchor" href="#导出为-markdown" aria-label="Permalink to &quot;导出为 Markdown&quot;">​</a></h3><p><strong>会话导出</strong>：在右侧会话列表右键点击会话 → 「导出会话」，可选择格式并预览导出内容。</p><p><strong>分支导出</strong>：在消息的操作菜单中点击「更多」→「导出分支」，可从此节点开始导出从根节点到该消息的路径。支持丰富的 Markdown 格式：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span># 对话记录: 会话名称</span></span>
<span class="line"><span></span></span>
<span class="line"><span>导出时间：2026-05-08 10:30:00</span></span>
<span class="line"><span>消息统计：共 12 条消息</span></span>
<span class="line"><span>对话参与者：用户: 小林 | 智能体: 助手</span></span>
<span class="line"><span></span></span>
<span class="line"><span>---</span></span>
<span class="line"><span>## 🧑 小林 (10:30)</span></span>
<span class="line"><span>你好！</span></span>
<span class="line"><span></span></span>
<span class="line"><span>## 🤖 助手 (10:31)</span></span>
<span class="line"><span>你好！有什么可以帮你的？</span></span></code></pre></div><p>导出内容包括：</p><ul><li>会话基本信息（名称、创建时间）</li><li>参与者和智能体信息</li><li>每条消息：发送者、时间戳、内容</li><li>Token 使用统计</li><li>模型信息</li><li>附件列表</li></ul><p><strong>完整会话树导出</strong>：导出包含所有分支的完整会话，使用 Markdown 列表树状结构展示：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- **🤖 助手** (10:31)</span></span>
<span class="line"><span>  这是第一条回复</span></span>
<span class="line"><span>  *[此处产生了 2 条不同的对话路径]*</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  - **🧑 小林** (10:32)</span></span>
<span class="line"><span>    追问内容...</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  - **🧑 小林** (10:33)</span></span>
<span class="line"><span>    另一个方向的追问...</span></span></code></pre></div><h3 id="导出为-json" tabindex="-1">导出为 JSON <a class="header-anchor" href="#导出为-json" aria-label="Permalink to &quot;导出为 JSON&quot;">​</a></h3><p>分支导出也支持 JSON 格式，保留完整的结构化数据，适合程序化处理或数据备份：</p><div class="language-json vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;session&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;name&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;会话名称&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">    &quot;createdAt&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-05-08T02:30:00.000Z&quot;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;exportTime&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;2026-05-08T10:30:00.000Z&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;messageCount&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">12</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  &quot;messages&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#B31D28;--shiki-light-font-style:italic;--shiki-dark:#FDAEB7;--shiki-dark-font-style:italic;">...</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><h3 id="导出选项" tabindex="-1">导出选项 <a class="header-anchor" href="#导出选项" aria-label="Permalink to &quot;导出选项&quot;">​</a></h3><p>导出时可以从对话框中选择：</p><ul><li><strong>包含预设消息</strong>：是否包含 Agent 的预设消息</li><li><strong>合并预设</strong>：将预设消息与会话消息合并显示，或分开显示</li><li><strong>包含用户档案信息</strong>：参与者名称和头像</li><li><strong>包含智能体信息</strong>：使用的 Agent 名称</li><li><strong>包含模型信息</strong>：使用的模型和渠道</li><li><strong>包含 Token 使用统计</strong></li><li><strong>包含附件列表</strong></li><li><strong>包含错误信息</strong></li><li><strong>范围选择</strong>：只导出指定范围内的消息</li></ul><blockquote><p>TODO: 截图 — 导出选项对话框</p></blockquote><h2 id="agent-导出" tabindex="-1">Agent 导出 <a class="header-anchor" href="#agent-导出" aria-label="Permalink to &quot;Agent 导出&quot;">​</a></h2><h3 id="导出-agent-配置" tabindex="-1">导出 Agent 配置 <a class="header-anchor" href="#导出-agent-配置" aria-label="Permalink to &quot;导出 Agent 配置&quot;">​</a></h3><p>在智能体编辑器中可以将 Agent 导出为共享文件：</p><ul><li>支持 JSON 格式</li><li>可选择是否包含资产文件（头像、附件等）</li><li>支持 ZIP 打包（包含资产目录）</li><li>支持 PNG 格式（SillyTavern 兼容的角色卡）</li></ul><h3 id="导出代理应用" tabindex="-1">导出代理应用 <a class="header-anchor" href="#导出代理应用" aria-label="Permalink to &quot;导出代理应用&quot;">​</a></h3><p>导出的 Agent 文件可以在设备之间迁移，或分享给其他用户。</p><h2 id="导入" tabindex="-1">导入 <a class="header-anchor" href="#导入" aria-label="Permalink to &quot;导入&quot;">​</a></h2><h3 id="导入会话" tabindex="-1">导入会话 <a class="header-anchor" href="#导入会话" aria-label="Permalink to &quot;导入会话&quot;">​</a></h3><p>目前支持从文件加载之前保存的完整会话备份。</p><h3 id="导入-agent" tabindex="-1">导入 Agent <a class="header-anchor" href="#导入-agent" aria-label="Permalink to &quot;导入 Agent&quot;">​</a></h3><ol><li>在 Agent 管理中选择「导入 Agent」</li><li>选择要导入的文件（JSON / ZIP / PNG 角色卡）</li><li>系统会自动<strong>预检</strong>：检查冲突的名称、模型兼容性等</li><li>解决冲突后确认导入</li></ol><p><strong>预检详情</strong>：</p><ul><li>检测与现有 Agent 的名称冲突</li><li>检查使用的模型在本地是否可用</li><li>列出导入的资产文件列表</li><li>显示包含的预设消息数量</li></ul><h3 id="从-sillytavern-导入角色卡" tabindex="-1">从 SillyTavern 导入角色卡 <a class="header-anchor" href="#从-sillytavern-导入角色卡" aria-label="Permalink to &quot;从 SillyTavern 导入角色卡&quot;">​</a></h3><p>支持导入 SillyTavern 格式的 PNG 角色卡（V2 格式）：</p><ol><li>在创建 Agent 时选择「导入 SillyTavern 角色卡」</li><li>选择 <code>.png</code> 文件</li><li>系统会自动解析角色信息（名称、描述、预设消息）和嵌入的资产文件</li></ol><h3 id="批量导入" tabindex="-1">批量导入 <a class="header-anchor" href="#批量导入" aria-label="Permalink to &quot;批量导入&quot;">​</a></h3><p>导入功能支持单个文件和批量文件同时处理。</p><h2 id="数据迁移" tabindex="-1">数据迁移 <a class="header-anchor" href="#数据迁移" aria-label="Permalink to &quot;数据迁移&quot;">​</a></h2><h3 id="跨设备迁移" tabindex="-1">跨设备迁移 <a class="header-anchor" href="#跨设备迁移" aria-label="Permalink to &quot;跨设备迁移&quot;">​</a></h3><p>推荐使用 Agent 导出 + 会话导出的方式在设备间迁移数据：</p><ol><li>在旧设备上导出需要迁移的 Agent 和会话</li><li>将导出的文件传输到新设备</li><li>在新设备上分别导入</li><li>重新关联 Agent 使用的服务渠道和模型</li></ol><h3 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h3><ul><li>导出的 Agent 不包含 API Key 等敏感信息</li><li>导入后需要重新选择可用的模型（如果原模型在目标设备上不存在）</li><li>资产文件在导出为 JSON 时不包含实际文件内容，需使用 ZIP 模式</li></ul><h2 id="相关阅读" tabindex="-1">相关阅读 <a class="header-anchor" href="#相关阅读" aria-label="Permalink to &quot;相关阅读&quot;">​</a></h2><ul><li><a href="./sessions">会话管理</a> — 管理需要导出的会话</li><li><a href="./agents">智能体</a> — Agent 的导出配置详情</li></ul>`,44)])])}const g=s(e,[["render",t]]);export{c as __pageData,g as default};
